// Inactive (outline) and Active (filled) variants — inline SVG React components.

import type { SVGProps } from "react";
import { Images, MapPin, Sparkles } from "lucide-react";
import { L1_STRIP_ICON_STROKE_PX } from "@/app/components/l1StripIconTokens";

export type FigmaIconProps = SVGProps<SVGSVGElement> & {
  size?: number;
};

/**
 * Lucide `Sparkles` stroke tuned to match Figma L1 glyphs: they use `strokeWidth="1.5"` in a 20×20 viewBox.
 * Lucide roots are 24×24, so relative stroke = 1.5 × (24/20). Do **not** use `absoluteStrokeWidth` here — it
 * pins ~1.6px and reads heavier than the Figma-set at the same `size`.
 */
const BIRD_AI_LUCIDE_STROKE = (1.5 * 24) / 20;

/** Agents — Lucide `Sparkles` (Figma sparkle export did not scale cleanly at L1 sizes). */
export function FigmaIconBirdAI({ size = 20, className, ...props }: FigmaIconProps) {
  return (
    <Sparkles
      size={size}
      strokeWidth={BIRD_AI_LUCIDE_STROKE}
      className={className ? `shrink-0 ${className}` : "shrink-0"}
      aria-hidden
      {...props}
    />
  );
}

