/**
 * Listings — Lucide `MapPin` with the same stroke contract as `AeoSearchAiL1Icon` (`Search`) in the L1 rail,
 * so AEO/SEO rows stay aligned (the old filled Figma pin read smaller/lighter at L1 size).
 */
export function FigmaIconListings({ size = 20, className, ...props }: FigmaIconProps) {
  return (
    <MapPin
      {...props}
      size={size}
      strokeWidth={L1_STRIP_ICON_STROKE_PX}
      absoluteStrokeWidth
      className={className ? `shrink-0 ${className}` : "shrink-0"}
      aria-hidden
    />
  );
}

